/* Cart.updateCartItemQuantity */
UPDATE TB_CART_ITEM
SET QUANTITY = #{quantity},
    UPT_TM   = NOW()
WHERE ID = #{cartItemId}

/* Cart.updateCartSocialAccountId */
UPDATE TB_CART
SET SOCIAL_ACCOUNT_ID = #{socialAccountId},
    UPT_TM            = NOW()
WHERE ID = #{id}

/* Cart.updateCartStatus */
UPDATE TB_CART
SET STATUS = #{status},
    UPT_TM = NOW()
WHERE ID = #{id}
